use distributed_inference::pleromatic_knot_storage::KnotStorage;
use std::env;
use std::io::{self, Write};

/// knot-replay: Re-inject historical Pleromatic frames into the mesh.
///
/// Usage: knot-replay [limit] | aeon-monitor
fn main() -> io::Result<()> {
    let args: Vec<String> = env::args().collect();
    let limit = args
        .get(1)
        .and_then(|s| s.parse::<usize>().ok())
        .unwrap_or(10);

    let storage = KnotStorage::new("assets/memory");

    // Retrieve history (most recent first, so we reverse it to replay in chronological order)
    let frames = storage.history(limit)?;

    for frame in frames.iter().rev() {
        let encoded = bincode::serialize(frame).map_err(io::Error::other)?;
        io::stdout().write_all(&encoded)?;
        io::stdout().flush()?;

        // Optional: Add a small delay between replayed frames to avoid overloading the monitor
        std::thread::sleep(std::time::Duration::from_millis(50));
    }

    Ok(())
}
